import Vue from 'vue'
import Router from 'vue-router'

import "tailwindcss/tailwind.css"
import "animate.css/animate.min.css"
import { library } from '@fortawesome/fontawesome-svg-core'
import { faTimesCircle, faCommentDots, faArrowDown, faBrain, faCompass, faBook, faUserAstronaut, faEllipsisH, faCircle, faGamepad, faShoppingCart, faHeart } from '@fortawesome/free-solid-svg-icons'
import { FontAwesomeIcon, FontAwesomeLayers, FontAwesomeLayersText } from '@fortawesome/vue-fontawesome'

import App from './App.vue'
import store from './store/index'
import router from './router'

Vue.config.productionTip = false

library.add(faTimesCircle, faCommentDots, faArrowDown, faBrain, faCompass, faBook, faUserAstronaut, faEllipsisH, faCircle, faGamepad, faShoppingCart, faHeart)

Vue.component('font-awesome-icon', FontAwesomeIcon)
Vue.component('font-awesome-layers', FontAwesomeLayers)
Vue.component('font-awesome-layers-text', FontAwesomeLayersText)

Vue.use(Router)

new Vue({
  store,
  router,
  render: h => h(App),
}).$mount('#app')
