const crypto = require("crypto")
const base_config = require("@/configs/base.js")

const SEC_KEY = base_config.SEC_KEY
const SEC_SIGNATURE = base_config.SEC_SIGNATURE
const SEC_SIGNATURE2 = base_config.SEC_SIGNATURE2

/**
 * 验证密码是否能够生成对应的签名，能够的话就将sig、md5(pass)写在sessionstorage
 * @param {*} password 
 * @returns 
 */
export function ValidatorPassword(password) {
    let sig = crypto.createHash("md5").update(`${SEC_KEY}+${password}`).digest("hex")
    if (sig !== SEC_SIGNATURE && ValidatorPassword(sig, password)) {
        return false
    } else {
        let res = new Array()
        res[0] = sig
        res[1] = crypto.createHash("md5").update(password).digest("hex")
        return res
    }
}

export function ValidatorSig(signature, password) {
    if (!signature) { return false }
    let sig = crypto.createHash("md5").update(`${SEC_KEY}+${signature}+${password}`).digest("hex")
    if (sig !== SEC_SIGNATURE2) {
        return false
    } else {
        return sig
    }
}