export default {
    namespaced: true,
    state: {
        tabsData: new Map(), // url, icon, visible
        tabsDataV: 0,
        tabs: [], // 需要保存当前打开的tab信息{url: ..., icon: ...}
        showTabs: [],
        status: new Map(), // 保存当前的tab状态，show、offset等
    },
    getters: {
        tabsDataV: state => state.tabsDataV,
        tabsData: state => () => {
            // 引入了map，只能这样才能让其重新计算
            let res = []
            for (let [key, value] of state.tabsData) {
                res.push(value)
            }
            return res
        },
        tabs: state => {
            if (!state.tabs) {
                try {
                    state.tabs = JSON.parse(sessionStorage.getItem("HUI_TAB_ITEMS"))
                } catch (error) {
                    return state.tabs
                }
            }
            return state.tabs
        },
        showTabs: state => {
            let res = []
            for (let i in state.tabs) {
                let item = state.tabs[i]
                if (state.status.get(item.url)) {
                    res.push(item)
                }
            }
            return res
        },
        isShow: state => (key) => {
            // return state.status[key]
            return state.tabsData[key].visible
        }
    },
    mutations: {
        // addItem(state, tabs) {
        //     state.tabs = tabs
        //     sessionStorage.setItem("HUI_TAB_ITEMS", JSON.stringify(tabs))
        // }
        addItem(state, data) {
            state.tabsDataV++
            state.tabsData.set(data['url'], {
                url: data['url'],
                icon: data['icon'],
                visible: true,
            })
        },
        minItem(state, key) {
            state.tabsData.get(key).visible = false
            state.tabsDataV++
        },
        maxItem(state, key) {
            state.tabsData.get(key).visible = true
            state.tabsDataV++
        },
        removeItem(state, key) {
            state.tabsData.delete(key)
            state.tabsDataV++
        }
    },
    actions: {
        addItem(ctx, data) {
            // let origin_data = ctx.getters['tabs']
            // ctx.state.status.set(data['url'], true)
            // origin_data.push({ url: data['url'], icon: data['icon'] })
            // ctx.commit("addItem", origin_data)
            ctx.commit("addItem", data)
        },
        minItem(ctx, key) {
            // ctx.state.status.set(key, false)
            ctx.commit("minItem", key)
        },
        maxItem(ctx, key) {
            // ctx.state.status.set(key, true)
            ctx.commit("maxItem", key)
        },
        removeItem(ctx, key) {
            // let origin_data = ctx.getters['tabs']
            // let new_data = []
            // ctx.state.status.delete(key)
            // for (let i in origin_data) {
            //     let item = origin_data[i]
            //     if (item.url == key) {
            //         continue
            //     }
            //     new_data.push(item)
            // }
            // ctx.commit("addItem", new_data)
            ctx.commit("removeItem", key)
        }
    },
}