import { InitDB, addRecord, delRecord, readAll } from "@/store/db/like"

export default {
    namespaced: true,
    state: {
        _db: null,  // IDBDatabase
        record: undefined,
    },
    getters: {
        record: state => state.record
    },
    mutations: {
        initRecord(state, data) {
            state.record = [{
                tag: "default",
                data: data
            }]
        },
        addRecord(state) {
            // 重新计算record
            readAll(state._db)
                .then(resp => {
                    state.record = [{
                        tag: "default",
                        data: resp
                    }]
                }).catch(er => {
                    state.record = undefined
                })
        }
    },
    actions: {
        initLike(ctx) {
            return new Promise((resolve, reject) => {
                InitDB("ahui_compass_like")
                    .then(resp => {
                        ctx.state._db = resp
                        readAll(resp)
                            .then(re => {
                                ctx.commit("initRecord", re)
                                resolve(re)
                            }).catch(er => {
                                reject(er)
                            })
                    })
                    .catch(err => {
                        console.log(err)
                    })
            })
        }, // 初始化收藏列表
        addLike(ctx, data) {
            return new Promise((resolve, reject) => {
                addRecord(ctx.state._db, data.name, data.path, data.icon)
                    .then(resp => {
                        ctx.commit("addRecord")
                        resolve(resp)
                    })
                    .catch(err => {
                        reject(err)
                    })
            })
        }, // 新增收藏
        delLike(ctx, data) {


        }, // 删除收藏
    },
}