// 关于操作indexdb的辅助函数

// 数据表结构: name, path, icon

/**
 * 
 * @param {string} dbName
 * @param {Number} version  表示数据库的版本。如果省略，打开已有数据库时，默认为当前版本；新建数据库时，默认为1
 */
export function InitDB(dbName, version) {
    let request = window.indexedDB.open(dbName, version);
    return new Promise((resolve, reject) => {
        let db;
        request.onsuccess = function (event) {
            db = request.result;
            resolve(db)
        };
        request.onerror = function (event) {
            reject(Error('数据库打开报错'))
        };
        request.onupgradeneeded = function (event) {
            db = event.target.result;
            let objectStore = db.createObjectStore('like', { keyPath: 'id', autoIncrement: true }); // 自增
            objectStore.createIndex('name', 'name', { unique: true }); // Python.web框架.fastapi之类的
            // icon可以不建立索引
            objectStore.createIndex('path', 'path', { unique: true });
            // objectStore.createIndex('icon', 'icon', { unique: false });
        }
    })
}

/**
 * 新增记录
 * @param {IDBDatabase} db 
 * @param {*} name 
 * @param {*} path 
 * @param {*} icon 
 */
export function addRecord(db, name, path, icon) {
    // 是否只读readonly或读写readwrite
    var request = db.transaction(['like'], 'readwrite')
        .objectStore('like')
        .add({ name: name, path: path, icon: icon });
    return new Promise((resolve, reject) => {
        request.onsuccess = function (event) {
            resolve('数据写入成功');
        };

        request.onerror = function (event) {
            console.log(event)
            reject(Error('数据写入失败'));
        }
    })

}

export function FindByName(db, name) {
    let request = db.transaction(['like'], 'readonly')
        .objectStore('like').index('name').get(name);
    return new Promise((resolve, reject) => {
        request.onsuccess = function (e) {
            var result = e.target.result;
            if (result) {
                resolve(result)
            } else {
                reject(Error("没有该数据"))
            }
        }
    })

}

/**
 * 根据name删除字段
 * @param {IDBDatabase} db 
 * @param {string} name 
 */
export function delRecord(db, name) {
    return new Promise((resolve, reject) => {
        FindByName(db, name)
            .then(resp => {
                let request = db.transaction(['like'], 'readwrite')
                    .objectStore('like')
                    .delete(resp.id);
                request.onsuccess = function (e) {
                    resolve("删除成功")
                }
                request.onerror = function (e) {
                    reject(Error("删除失败"))
                }
            })
            .catch(err => {
                reject(err)
            })
    })

}

export function readAll(db) {
    /**
     * 大bug，onsuccess会多次调用，而不是调用一次然后移动游标
     */
    let request = db.transaction('like').objectStore('like').openCursor();
    // console.log("执行readAll")
    return new Promise((resolve, reject) => {
        let res = []

        request.onsuccess = function (event) {

            let cursor = event.target.result;
            // console.log("执行readAllEEE")

            if (cursor) {
                res.push({
                    id: cursor.key,
                    name: cursor.value.name,
                    path: cursor.value.path,
                    icon: cursor.value.icon,
                })
                cursor.continue();
            } else {
                resolve(res)
            }
        };

        request.onerror = function (e) {
            reject(Error("获取所有数据失败"))
        }
    })



}


