import Router from 'vue-router'
import store from '@/store/index'

import { ValidatorSig } from '@/utils/sec'

const router = new Router({
    // mode: "history",
    routes: [{
        path: "/",
        name: "首页",
        redirect: "/compass",
        // component: () => import("@/views/home/Main.vue"),
        // meta: { secret: true }
    }, {
        path: "/compass",
        name: "导航页",
        component: () => import("@/views/compass/Main.vue"),
        meta: { secret: false }
    }, {
        path: "/blog",
        name: "文章页",
        component: () => import("@/views/home/Main.vue"),
        meta: { secret: true }
    },
    {
        path: "/cart",
        name: "订单页",
        component: () => import("@/views/cart/Main.vue"),
        meta: { secret: true }
    }, {
        path: "/secret",
        name: "该页面不予访问",
        component: () => import("@/views/secret/Main.vue"),
        meta: { secret: false }
    }]
})

router.beforeEach((to, from, next) => {
    if (to.meta.secret && !ValidatorSig(store.getters["secSIG"], store.getters["secPWD"])) {
        next({ path: `/secret?redirect=${to.path}` });
    } else {
        next();
    }
})

export default router